| deity = {{jalink|Amatariwake-no-Mikoto}}<br />{{jalink|Shinatsuhiko|Q1073925|Shinatsuhiko-no-Mikoto and Shinatsuhime-no-Mikoto}}
| status = {{jalink|Shikinaisha}} (small), former {{jalink|gosha|Q134917316}}
| founded = (trad.) age of the gods
| architecture = {{jalink|nagare-zukuri|Q210684}}
| annual_festival = Third Sunday of April
